  1	/**
  2	 * Implements a multi-select typeahead component with checkboxes, enabling users to filter and select multiple options.
  3	 * Utilizes PatternFly for UI consistency and accessibility.
  4	 *
  5	 * @module typeaheadCheckboxes
  6	 */
  7	import React, { useEffect, useRef, useState } from 'react';
  8	import {
  9	  Select,
 10	  SelectOption,
 11	  SelectList,
 12	  type SelectOptionProps,
 13	  MenuToggle,
 14	  type MenuToggleElement,
 15	  TextInputGroup,
 16	  TextInputGroupMain,
 17	  TextInputGroupUtilities,
 18	  Button
 19	} from '@patternfly/react-core';
 20	import { TimesIcon } from '@patternfly/react-icons/';
 21	
 22	interface TypeaheadCheckboxesProps {
 23	  onChange?: (selections: string[]) => void;
 24	  options: { value: string; label: string }[];
 25	  selectedOptions?: string[];
 26	  placeholder?: string;
 27	  menuToggleOuiaId?: number | string;
 28	  maxSelections?: number;
 29	}
 30	
 31	const TypeaheadCheckboxes: React.FC<TypeaheadCheckboxesProps> = ({
 32	  onChange = Function.prototype,
 33	  options,
 34	  selectedOptions = [],
 35	  placeholder = '0 items selected',
 36	  menuToggleOuiaId,
 37	  maxSelections = Infinity
 38	}) => {
 39	  const [isOpen, setIsOpen] = useState(false);
 40	  const [inputValue, setInputValue] = useState<string>('');
 41	  const [selectOptions, setSelectOptions] = useState<SelectOptionProps[]>(options);
 42	  const [focusedItemIndex, setFocusedItemIndex] = useState<number | null>(null);
 43	  const [activeItem, setActiveItem] = useState<string | null>(null);
 44	  const [activePlaceholder, setActivePlaceholder] = useState(placeholder);
 45	  const textInputRef = useRef<HTMLInputElement>(null);
 46	  const justSelectedRef = useRef(false);
 47	
 48	  useEffect(() => {
 49	    let filteredOptions = options;
 50	
 51	    if (inputValue) {
 52	      filteredOptions = options.filter(option => option.label.toLowerCase().includes(inputValue.toLowerCase()));
 53	
 54	      if (!filteredOptions.length) {
 55	        setSelectOptions([
 56	          {
 57	            isDisabled: false,
 58	            children: `No results found for "${inputValue}"`,
 59	            value: 'no results'
 60	          }
 61	        ]);
 62	        return;
 63	      }
 64	
 65	      if (!isOpen && !justSelectedRef.current) {
 66	        setIsOpen(true);
 67	      }
 68	    }
 69	
 70	    const selectedOptionsFiltered = filteredOptions.filter(option => selectedOptions.includes(option.value));
 71	    const unselectedOptions = filteredOptions
 72	      .filter(option => !selectedOptions.includes(option.value))
 73	      .sort((a, b) => a.label.localeCompare(b.label));
 74	
 75	    const newOptions = [...selectedOptionsFiltered, ...unselectedOptions];
 76	
 77	    setSelectOptions(prev => {
 78	      // More efficient comparison - just check values in order
 79	      if (prev.length !== newOptions.length) {
 80	        return newOptions;
 81	      }
 82	      const hasChanged = prev.some((option, index) => option.value !== newOptions[index]?.value);
 83	      return hasChanged ? newOptions : prev;
 84	    });
 85	
 86	    setFocusedItemIndex(null);
 87	    setActiveItem(null);
 88	  }, [inputValue, isOpen, options, selectedOptions]);
 89	  const handleMenuArrowKeys = (key: string) => {
 90	    let indexToFocus;
 91	
 92	    if (isOpen) {
 93	      if (key === 'ArrowUp') {
 94	        // When no index is set or at the first index, focus to the last, otherwise decrement focus index
 95	        if (focusedItemIndex === null || focusedItemIndex === 0) {
 96	          indexToFocus = selectOptions.length - 1;
 97	        } else {
 98	          indexToFocus = focusedItemIndex - 1;
 99	        }
100	      }
101	
102	      if (key === 'ArrowDown') {
103	        // When no index is set or at the last index, focus to the first, otherwise increment focus index
104	        if (focusedItemIndex === null || focusedItemIndex === selectOptions.length - 1) {
105	          indexToFocus = 0;
106	        } else {
107	          indexToFocus = focusedItemIndex + 1;
108	        }
109	      }
110	
111	      setFocusedItemIndex(indexToFocus);
112	      const focusedItem = selectOptions.filter(option => !option.isDisabled)[indexToFocus];
113	      setActiveItem(`select-multi-typeahead-checkbox-${String(focusedItem.value).replace(' ', '-')}`);
114	    }
115	  };
116	
117	  const onInputKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
118	    const enabledMenuItems = selectOptions.filter(menuItem => !menuItem.isDisabled);
119	    const [firstMenuItem] = enabledMenuItems;
120	    const focusedItem = focusedItemIndex ? enabledMenuItems[focusedItemIndex] : firstMenuItem;
121	
122	    switch (event.key) {
123	      // Select the first available option
124	      case 'Enter':
125	        if (!isOpen) {
126	          setIsOpen(prevIsOpen => !prevIsOpen);
127	        } else if (isOpen && focusedItem.value !== 'no results') {
128	          onSelect(focusedItem.value as string);
129	        }
130	        break;
131	      case 'Tab':
132	      case 'Escape':
133	        setIsOpen(false);
134	        setActiveItem(null);
135	        break;
136	      case 'ArrowUp':
137	      case 'ArrowDown':
138	        event.preventDefault();
139	        handleMenuArrowKeys(event.key);
140	        break;
141	    }
142	  };
143	
144	  const onToggleClick = () => {
145	    setIsOpen(!isOpen);
146	  };
147	
148	  const onTextInputChange = (_event: React.FormEvent<HTMLInputElement>, value: string) => {
149	    setInputValue(value);
150	  };
151	
152	  const onSelect = (value: string) => {
153	    if (!value || value === 'no results') {
154	      return;
155	    }
156	
157	    let newSelected: string[];
158	
159	    if (!selectedOptions.includes(value)) {
160	      if (selectedOptions.length >= maxSelections) {
161	        return;
162	      }
163	      newSelected = [...selectedOptions, value];
164	    } else {
165	      newSelected = selectedOptions.filter(v => v !== value);
166	    }
167	
168	    onChange(newSelected);
169	
170	    justSelectedRef.current = true;
171	
172	    if (maxSelections === 1 || newSelected.length >= maxSelections) {
173	      setIsOpen(false);
174	    }
175	
176	    setInputValue('');
177	    textInputRef.current?.focus();
178	
179	    justSelectedRef.current = false;
180	  };
181	
182	  useEffect(() => {
183	    setActivePlaceholder(selectedOptions.length ? `${selectedOptions.length} items selected` : placeholder);
184	  }, [selectedOptions, placeholder]);
185	
186	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
187	    <MenuToggle
188	      variant="typeahead"
189	      onClick={onToggleClick}
190	      innerRef={toggleRef}
191	      isExpanded={isOpen}
192	      isFullWidth
193	      data-ouia-component-id={menuToggleOuiaId}
194	    >
195	      <TextInputGroup isPlain>
196	        <TextInputGroupMain
197	          value={inputValue}
198	          onClick={onToggleClick}
199	          onChange={onTextInputChange}
200	          onKeyDown={onInputKeyDown}
201	          id="multi-typeahead-select-checkbox-input"
202	          autoComplete="off"
203	          innerRef={textInputRef}
204	          placeholder={activePlaceholder}
205	          {...(activeItem && { 'aria-activedescendant': activeItem })}
206	          role="combobox"
207	          isExpanded={isOpen}
208	          aria-controls="select-multi-typeahead-checkbox-listbox"
209	          data-ouia-component-id="credentials_list_input"
210	        />
211	        <TextInputGroupUtilities>
212	          {selectedOptions.length > 0 && (
213	            <Button
214	              variant="plain"
215	              onClick={() => {
216	                setInputValue('');
217	                onChange([]);
218	                textInputRef?.current?.focus();
219	              }}
220	              aria-label="Clear input value"
221	              ouiaId="credentials_list_clear_button"
222	            >
223	              <TimesIcon aria-hidden />
224	            </Button>
225	          )}
226	        </TextInputGroupUtilities>
227	      </TextInputGroup>
228	    </MenuToggle>
229	  );
230	
231	  return (
232	    <Select
233	      role="menu"
234	      id="multi-typeahead-checkbox-select"
235	      isOpen={isOpen}
236	      selected={selectedOptions}
237	      onSelect={(ev, selection) => onSelect(selection as string)}
238	      onOpenChange={() => setIsOpen(false)}
239	      toggle={toggle}
240	    >
241	      <SelectList id="select-multi-typeahead-checkbox-listbox">
242	        {selectOptions.map((option, index) => (
243	          <SelectOption
244	            {...(!option.isDisabled && { hasCheckbox: true })}
245	            isSelected={selectedOptions.includes(option.value)}
246	            key={option.value || option.children}
247	            isFocused={focusedItemIndex === index}
248	            className={option.className}
249	            id={`select-multi-typeahead-${String(option.value).replace(' ', '-')}`}
250	            // Pass children before spreading ...option so it can be overridden by the consumer
251	            // eslint-disable-next-line react/no-children-prop
252	            children={option.label}
253	            {...option}
254	            ref={null}
255	          />
256	        ))}
257	      </SelectList>
258	    </Select>
259	  );
260	};
261	
262	export { TypeaheadCheckboxes as default, TypeaheadCheckboxes, type TypeaheadCheckboxesProps };

